    '#bf-${c} input:focus,#bf-${c} select:focus,#bf-${c} textarea:focus{outline:none;border-color:#0073ea;box-shadow:0 0 0 3px rgba(0,115,234,.1)}',
    '#bf-${c} .bf-submit{width:100%;padding:.8rem;background:#0073ea;color:#fff;border:none;border-radius:8px;font-size:1rem;font-weight:600;cursor:pointer;margin-top:.5rem;transition:background .2s,transform .1s}',
    '#bf-${c} .bf-submit:hover{background:#005ec9}',
